/* Layout */
import Layout from '@/layout'
/**
 * 动态路由定义
 */
let dynamicRouter = {
    routes: [
        {
            path: "",
            name: "layout",
            component: () => import("@/layout/index"),
            children: []
        }
    ]
}

export default dynamicRouter;
